// ============================================================
// Parse JotForm Data v5 — Supabase Edition
// ============================================================

const formData = $input.first().json.body;

function normalizeList(val) {
  if (!val) return '';
  if (Array.isArray(val)) return val.filter(Boolean).join(', ');
  return String(val).trim();
}

function clean(val, fallback = '') {
  if (!val) return fallback;
  return String(val).trim() || fallback;
}

const extractedData = {
  // Section 1: Business Information
  company_name:         clean(formData.q4_hvacCompany || formData['q4_hvacCompany']),
  owner_name:           clean(formData.q54_ownerName || formData['q54_ownerName']),
  main_phone:           clean(formData.q6_mainCompany || formData['q6_mainCompany']),
  client_email:         clean(formData.q5_emailAddress || formData['q5_emailAddress']),
  website:              clean(formData.q7_companyWebsite || formData['q7_companyWebsite']),
  years_in_business:    clean(formData.q8_yearsIn || formData['q8_yearsIn']),
  timezone:             clean(formData.q34_timezone || formData['q34_timezone'], 'America/Chicago'),
  services_offered:     normalizeList(formData.q13_servicesOffered || formData['q13_servicesOffered']),
  brands_serviced:      normalizeList(formData.q14_brandsequipmentServiced || formData['q14_brandsequipmentServiced']),
  service_area:         clean(formData.q16_primaryService || formData['q16_primaryService']),
  service_area_radius:  clean(formData.q40_serviceAreaRadius || formData['q40_serviceAreaRadius']),
  certifications:       normalizeList(formData.q29_certifications || formData['q29_certifications']),
  licensed_insured:     clean(formData.q28_licensedAnd || formData['q28_licensedAnd'], 'Yes'),

  // Section 2: AI Receptionist Configuration
  agent_name:           clean(formData.q10_aiAgent10 || formData['q10_aiAgent10']),
  voice_gender:         clean(formData.q11_aiVoice || formData['q11_aiVoice'], 'Female'),
  custom_greeting:      clean(formData.q38_customGreeting || formData['q38_customGreeting']),
  company_tagline:      clean(formData.q39_companyTagline || formData['q39_companyTagline']),
  business_hours:       clean(formData.q17_businessHours || formData['q17_businessHours']),
  response_time:        clean(formData.q18_typicalResponse || formData['q18_typicalResponse']),
  emergency_service:    clean(formData.q20_247Emergency || formData['q20_247Emergency'], 'No'),
  emergency_phone:      clean(formData.q21_emergencyAfterhours || formData['q21_emergencyAfterhours']),
  after_hours_behavior: clean(formData.q22_afterhoursBehavior || formData['q22_afterhoursBehavior']),

  // Section 3: Call Handling & Pricing
  pricing_policy:       clean(formData.q42_pricingPolicy || formData['q42_pricingPolicy'], 'We provide free quotes on-site'),
  diagnostic_fee:       clean(formData.q41_diagnosticFee || formData['q41_diagnosticFee']),
  standard_fees:        clean(formData.q43_standardFees || formData['q43_standardFees']),
  free_estimates:       clean(formData.q24_freeEstimates || formData['q24_freeEstimates'], 'Yes - always free'),
  do_not_service:       clean(formData.q57_doNotServiceList || formData['q57_doNotServiceList']),
  transfer_phone:       clean(formData.q48_transferPhone || formData['q48_transferPhone']),
  transfer_triggers:    normalizeList(formData.q49_transferTriggers || formData['q49_transferTriggers']),
  transfer_behavior:    clean(formData.q50_transferBehavior || formData['q50_transferBehavior'], 'Try once - take message if no answer'),

  // Section 4: Lead Capture & Notifications
  lead_contact_method:  clean(formData.q31_leadContact || formData['q31_leadContact'], 'Both'),
  lead_phone:           clean(formData.q32_leadNotification || formData['q32_leadNotification']),
  lead_email:           clean(formData.q33_leadNotification33 || formData['q33_leadNotification33']),

  // Section 5: Branding, Promotions & Extras
  google_review_rating: clean(formData.q55_googleReviewRating || formData['q55_googleReviewRating']),
  google_review_count:  clean(formData.q56_googleReviewCount || formData['q56_googleReviewCount']),
  unique_selling_points: clean(formData.q51_uniqueSellingPoints || formData['q51_uniqueSellingPoints']),
  current_promotion:    clean(formData.q52_currentPromotion || formData['q52_currentPromotion']),
  seasonal_services:    clean(formData.q53_seasonalServices || formData['q53_seasonalServices']),
  membership_program:   clean(formData.q58_membershipProgramName || formData['q58_membershipProgramName']),
  maintenance_plans:    clean(formData.q46_maintenancePlans || formData['q46_maintenancePlans'], 'No'),
  financing_available:  clean(formData.q25_financingAvailable || formData['q25_financingAvailable'], 'No'),
  financing_details:    clean(formData.q44_financingDetails || formData['q44_financingDetails']),
  warranty:             clean(formData.q26_serviceWarranties || formData['q26_serviceWarranties'], 'Yes'),
  warranty_details:     clean(formData.q27_warrantyDetails || formData['q27_warrantyDetails']),
  payment_methods:      normalizeList(formData.q45_paymentMethods || formData['q45_paymentMethods']),
  additional_info:      clean(formData.q37_additionalInfo || formData['q37_additionalInfo'])
};

// === Build company info block for the Retell prompt ===
let companyInfoBlock = `## Company Overview\n`;
companyInfoBlock += `- Company Name: ${extractedData.company_name}\n`;
if (extractedData.main_phone) companyInfoBlock += `- Main Phone: ${extractedData.main_phone}\n`;
if (extractedData.years_in_business) companyInfoBlock += `- Experience: ${extractedData.years_in_business} years in business\n`;
if (extractedData.owner_name) companyInfoBlock += `- Owner/Manager: ${extractedData.owner_name}\n`;
if (extractedData.company_tagline) companyInfoBlock += `- Tagline: ${extractedData.company_tagline}\n`;
if (extractedData.website) companyInfoBlock += `- Website: ${extractedData.website}\n`;
companyInfoBlock += `- Licensed & Insured: ${extractedData.licensed_insured}\n`;
if (extractedData.certifications) companyInfoBlock += `- Certifications: ${extractedData.certifications}\n`;

companyInfoBlock += `\n## Services\n`;
if (extractedData.services_offered) companyInfoBlock += `- Services: ${extractedData.services_offered}\n`;
if (extractedData.brands_serviced) companyInfoBlock += `- Brands Serviced: ${extractedData.brands_serviced}\n`;
if (extractedData.service_area) {
  let areaLine = extractedData.service_area;
  if (extractedData.service_area_radius) areaLine += ` (within ${extractedData.service_area_radius})`;
  companyInfoBlock += `- Service Area: ${areaLine}\n`;
}
if (extractedData.do_not_service) companyInfoBlock += `- DO NOT Service: ${extractedData.do_not_service}\n`;

companyInfoBlock += `\n## Hours & Availability\n`;
if (extractedData.business_hours) companyInfoBlock += `- Business Hours: ${extractedData.business_hours}\n`;
if (extractedData.response_time) companyInfoBlock += `- Typical Response Time: ${extractedData.response_time}\n`;

companyInfoBlock += `\n## Pricing & Policies\n`;
companyInfoBlock += `- Pricing Policy: ${extractedData.pricing_policy}\n`;
if (extractedData.diagnostic_fee) companyInfoBlock += `- Diagnostic/Service Call Fee: ${extractedData.diagnostic_fee} (applied to repair if customer proceeds)\n`;
if (extractedData.standard_fees) companyInfoBlock += `- Set Fees (ONLY share these specific fees when asked): ${extractedData.standard_fees}\n`;
companyInfoBlock += `- Free Estimates: ${extractedData.free_estimates}\n`;
if (extractedData.financing_available !== 'No') {
  let finLine = `Financing Available: Yes`;
  if (extractedData.financing_details) finLine += ` - ${extractedData.financing_details}`;
  companyInfoBlock += `- ${finLine}\n`;
}
if (extractedData.warranty !== 'No') {
  let warLine = `Warranty: Yes`;
  if (extractedData.warranty_details) warLine += ` - ${extractedData.warranty_details}`;
  companyInfoBlock += `- ${warLine}\n`;
}
if (extractedData.maintenance_plans !== 'No') {
  let mainLine = `Maintenance Plans: Available`;
  if (extractedData.membership_program) mainLine += ` - "${extractedData.membership_program}"`;
  companyInfoBlock += `- ${mainLine}\n`;
}
if (extractedData.payment_methods) companyInfoBlock += `- Payment Methods: ${extractedData.payment_methods}\n`;

if (extractedData.emergency_service && extractedData.emergency_service !== 'No') {
  companyInfoBlock += `\n## Emergency Service\n`;
  companyInfoBlock += `- Emergency Service: ${extractedData.emergency_service}\n`;
  if (extractedData.emergency_phone) companyInfoBlock += `- Emergency Contact: ${extractedData.emergency_phone}\n`;
  if (extractedData.after_hours_behavior) companyInfoBlock += `- After Hours Handling: ${extractedData.after_hours_behavior}\n`;
}

if (extractedData.google_review_rating || extractedData.current_promotion || extractedData.seasonal_services || extractedData.unique_selling_points) {
  companyInfoBlock += `\n## Promotions & Highlights\n`;
  if (extractedData.google_review_rating && extractedData.google_review_rating !== 'Not listed on Google') {
    let reviewLine = `Google Rating: ${extractedData.google_review_rating} stars`;
    if (extractedData.google_review_count && extractedData.google_review_count !== 'Not listed on Google') {
      reviewLine += ` with ${extractedData.google_review_count} reviews`;
    }
    companyInfoBlock += `- ${reviewLine}\n`;
  }
  if (extractedData.current_promotion) companyInfoBlock += `- Current Promotion: ${extractedData.current_promotion}\n`;
  if (extractedData.seasonal_services) companyInfoBlock += `- Seasonal Services: ${extractedData.seasonal_services}\n`;
  if (extractedData.unique_selling_points) companyInfoBlock += `- Why Choose Us: ${extractedData.unique_selling_points}\n`;
}

if (extractedData.additional_info) {
  companyInfoBlock += `\n## Additional Notes\n`;
  companyInfoBlock += `${extractedData.additional_info}\n`;
}

return {
  ...extractedData,
  companyInfoBlock,
  timestamp: new Date().toISOString()
};

// ============================================================
// Build Retell Prompt v5 — Supabase Edition
// ============================================================
// Removed Google Sheets settings dependency
// Transfer number: lead_phone default, emergency_phone override
// ============================================================

const data = $input.first().json;

const companyName        = data.company_name || 'HVAC Company';
const companyPhone       = data.main_phone || '';
const companyWebsite     = data.website || '';
const yearsInBusiness    = data.years_in_business || '';
const agentName          = data.agent_name || `${companyName} Receptionist`;
const voiceGender        = (data.voice_gender || 'female').toLowerCase();
const servicesOffered    = data.services_offered || '';
const brandsServiced     = data.brands_serviced || '';
const serviceArea        = data.service_area || '';
const serviceAreaRadius  = data.service_area_radius || '';
const businessHours      = data.business_hours || '';
const responseTime       = data.response_time || '';
const emergency247       = data.emergency_service || 'No';
const emergencyPhone     = data.emergency_phone || '';
const afterHoursBehavior = data.after_hours_behavior || '';
const freeEstimates      = data.free_estimates || 'Yes - always free';
const diagnosticFee      = data.diagnostic_fee || '';
const pricingPolicy      = data.pricing_policy || 'We provide free quotes on-site';
const standardFees       = data.standard_fees || '';
const financingAvailable = data.financing_available || 'No';
const financingDetails   = data.financing_details || '';
const warranty           = data.warranty || 'Yes';
const warrantyDetails    = data.warranty_details || '';
const licensedInsured    = data.licensed_insured || 'Yes';
const certifications     = data.certifications || '';
const paymentMethods     = data.payment_methods || '';
const maintenancePlans   = data.maintenance_plans || 'No';
const leadContactMethod  = data.lead_contact_method || 'Both';
const leadPhone          = data.lead_phone || '';
const leadEmail          = data.lead_email || '';
const customGreeting     = data.custom_greeting || '';
const companyTagline     = data.company_tagline || '';
const transferPhone      = data.transfer_phone || '';
const transferTriggers   = data.transfer_triggers || 'Caller requests a live person, Emergency situation';
const transferBehavior   = data.transfer_behavior || 'Try once - take message if no answer';
const uniqueSellingPts   = data.unique_selling_points || '';
const currentPromotion   = data.current_promotion || '';
const seasonalServices   = data.seasonal_services || '';
const additionalNotes    = data.additional_info || '';
const companyInfoBlock   = data.companyInfoBlock || '';
const ownerName          = data.owner_name || '';
const googleReviewRating = data.google_review_rating || '';
const googleReviewCount  = data.google_review_count || '';
const doNotService       = data.do_not_service || '';
const membershipProgram  = data.membership_program || '';
const industryType       = data.industry_type || 'HVAC';
const testMode           = false;

// === Voice selection ===
const voiceMap = { female: 'retell-Sloane', male: 'retell-Nico' };
const voiceId = voiceMap[voiceGender] || 'retell-Sloane';

// === Transfer number: use lead_phone by default, emergency_phone as override ===
const rawTransferPhone = emergencyPhone || leadPhone;
const transferNumber = rawTransferPhone
  ? (rawTransferPhone.startsWith('+') ? rawTransferPhone : `+1${rawTransferPhone.replace(/\D/g, '')}`)
  : '+10000000000';

// ============================================================
// BUILD PRICING RESPONSE INSTRUCTIONS
// ============================================================
let shareableFees = '';
if (diagnosticFee) shareableFees += `
- Diagnostic/Service Call Fee: ${diagnosticFee} (gets applied to the repair if the customer proceeds)`;
if (standardFees) shareableFees += `
- Additional Set Fees: ${standardFees}`;

let pricingInstructions = '';
if (pricingPolicy === 'We provide free quotes on-site') {
  pricingInstructions = `When callers ask about pricing or cost:
- Say: "We provide free on-site quotes so our team can give you
  an accurate price based on your specific situation. Let me grab
  your details so we can get someone out to you."
- NEVER provide general service, repair, or installation prices.
- NEVER guess or estimate costs for any service.`;
  if (shareableFees) pricingInstructions += `

The ONLY fees you may mention (because the company has explicitly provided them):${shareableFees}

Only mention these if the caller specifically asks about them. Do NOT volunteer pricing.`;
} else if (pricingPolicy === 'We charge a diagnostic fee then quote') {
  pricingInstructions = `When callers ask about pricing or cost:
- Say: "We do have a ${diagnosticFee || 'service call'} fee for
  the initial visit, and that gets applied to the repair if you
  choose to move forward with us. Our technician will give you a
  full quote once they've assessed the situation."
- NEVER provide general repair or installation prices.
- NEVER guess or estimate costs beyond the set fees listed below.`;
  if (shareableFees) pricingInstructions += `

Set fees you may share when asked:${shareableFees}`;
} else {
  pricingInstructions = `When callers ask about pricing or cost:
- Say: "Our team will go over all the pricing with you so you get
  the most accurate information. Let me grab your details so we
  can get that set up for you."
- NEVER provide any prices, estimates, or cost ranges over the phone.
- NEVER guess or estimate costs for any service.`;
  if (shareableFees) pricingInstructions += `

Exception — the ONLY fees you may mention:${shareableFees}

Only mention these if the caller specifically asks. Do NOT volunteer pricing.`;
}

// ============================================================
// BUILD TRANSFER RULES
// ============================================================
const triggerList = transferTriggers.split(',').map(t => t.trim()).filter(Boolean);
let transferRules = `## CALL TRANSFER PROTOCOL

`;
transferRules += `Transfer destination: ${transferNumber}
`;
transferRules += `Transfer behavior: ${transferBehavior}

`;
transferRules += `Transfer the call ONLY when one of these conditions is met:
`;
triggerList.forEach((t, i) => { transferRules += `${i + 1}. ${t}
`; });
transferRules += `
For ALL other situations, collect the caller's information and let them know someone will follow up.`;
if (transferBehavior === 'Always take a message - never transfer') {
  transferRules += `

IMPORTANT: NEVER transfer calls. Always collect caller information and confirm someone from the team will call back.`;
}
if (ownerName) {
  transferRules += `

### Owner/Manager Reference
If a caller asks to speak with the owner or manager, their name is ${ownerName}. Say: "${ownerName} isn't available right now, but I can take a message and have them call you back — or I can transfer you to our team."`;
}

// ============================================================
// BUILD DO NOT SERVICE SECTION
// ============================================================
let doNotServiceSection = '';
if (doNotService) {
  doNotServiceSection = `
---

## SERVICES WE DO NOT PROVIDE

The following items are outside our scope of service:
${doNotService}

If a caller requests any of these, politely explain:
"I appreciate you reaching out, but unfortunately that's not something we service. I'd recommend reaching out to a specialist for that. Is there anything else I can help you with?"

Do NOT attempt to collect lead information for out-of-scope requests.
`;
}

// ============================================================
// BUILD PROMOTIONS / SELLING POINTS SECTION
// ============================================================
let promotionsSection = '';
if (currentPromotion || seasonalServices || uniqueSellingPts || (googleReviewRating && googleReviewRating !== 'Not listed on Google')) {
  promotionsSection = `
---

## PROMOTIONS & VALUE PROPOSITIONS

`;
  if (googleReviewRating && googleReviewRating !== 'Not listed on Google') {
    let reviewLine = `We have a ${googleReviewRating}-star rating on Google`;
    if (googleReviewCount && googleReviewCount !== 'Not listed on Google') reviewLine += ` with ${googleReviewCount.toLowerCase().replace('under ', 'nearly ')} reviews`;
    promotionsSection += `### Google Reviews
${reviewLine}.
Mention this naturally when a caller is comparing options or seems uncertain.

`;
  }
  if (currentPromotion) promotionsSection += `### Current Promotion
${currentPromotion}
Mention this naturally when a caller asks about the relevant service.

`;
  if (uniqueSellingPts) promotionsSection += `### Why Choose ${companyName}
${uniqueSellingPts}
Use these points when a caller seems to be comparing options. Weave them in naturally.

`;
  if (seasonalServices) promotionsSection += `### Seasonal Services
${seasonalServices}
Mention the relevant seasonal service if it matches what the caller needs.

`;
}

// ============================================================
// BUILD PAYMENT METHODS SECTION
// ============================================================
let paymentSection = '';
if (paymentMethods) {
  paymentSection = `
When callers ask about payment methods:
- Say: "We accept ${paymentMethods}."`;
  if (financingAvailable === 'Yes' && financingDetails) paymentSection += `
- If they ask about financing: "Yes, we offer financing — ${financingDetails}."`;
  else if (financingAvailable === 'Yes') paymentSection += `
- If they ask about financing: "Yes, we do offer financing options. Our team can go over the details with you."`;
  if (maintenancePlans !== 'No') {
    let maintLine = `
- If they ask about maintenance plans: "Yes, we do offer maintenance plans`;
    if (membershipProgram) maintLine += ` — our ${membershipProgram} program`;
    maintLine += `. Our team can go over the details and pricing with you."`;
    paymentSection += maintLine;
  }
}

// ============================================================
// GLOBAL PROMPT
// ============================================================
const globalPrompt = `## IDENTITY & TONE

You are ${agentName}, a virtual AI receptionist for ${companyName}.${companyTagline ? `
${companyName} — ${companyTagline}.` : ''}
You are warm, friendly and professional. Speak naturally, like a
helpful team member, not a robot. Always address callers by their
first name once you have it.

If asked whether you are a real person, be honest:
"I'm a virtual assistant, but I'm here to make sure you get
exactly the help you need."

---

## STYLE GUIDELINES

- Keep responses concise, one topic at a time
- Use simple, everyday language, no technical jargon
- Ask only one question at a time, always wait for the caller
  to respond before asking another
- Match the caller's energy — calm if they're calm,
  reassuring if they're stressed
- Be empathetic, especially with frustrated or worried callers
- Be patient with elderly callers or anyone who needs more time
- Vary your language naturally, avoid repeating the same phrases
- Never talk over the caller or rush them
- Adapt to the caller's pace and communication style
- Your goal is to make every caller feel heard, helped, and
  confident that someone will follow up with them

---

## CONTACT CONFIRMATION

Always confirm contact details back to the caller:

- Names: spell out letter by letter for any name that is uncommon
  or could be misheard
  "Your name is J-O-H-N, is that right?"
- Addresses: spell out street names that are uncommon or could be
  misheard. Skip spelling for generic street types such as Street,
  Drive, Avenue, Road, Lane, Boulevard
- Emails: "Your email is B-O-B dot S-M-I-T-H at gmail dot com?"
  Use "at", "dot", "dash", "underscore", do not spell these out.
  Skip spelling for common domains such as gmail, yahoo, hotmail,
  outlook
- Phone numbers: read back in groups
  "Your number is 404, 555, 1234, is that right?"
- Zip codes: always read back digit by digit
  "And the zip code is 3-0-3-0-1?"

---

## COMPANY INFORMATION

{{COMPANY_INFO_BLOCK}}

Use the information above to answer any company-specific questions
such as service areas, hours of operation, services offered, and
contact details. If a question about the company is NOT covered
above, do NOT guess or make up information. Say:
"That's a great question, one of our team members will be able
to answer that when they call you back."

---

## PRICING & QUOTING

${pricingInstructions}

---

${transferRules}

---

## PAYMENT & FINANCING
${paymentSection || `When callers ask about payment methods:
- Say: "Our team can go over payment options with you at the appointment."`}

---
${promotionsSection}
${doNotServiceSection}
## CRITICAL RULES — NEVER BREAK THESE

- NEVER ask more than one question at a time
- NEVER make up prices, estimates, or timeframes unless price ranges
  are explicitly listed in the company information
- NEVER diagnose ${industryType} problems or recommend specific repairs
- NEVER promise availability or same-day service unless explicitly
  stated in the company information
- NEVER guess answers to company-specific questions not found in
  the company information
- NEVER continue a conversation with obvious spam or robocalls,
  end politely
- NEVER transfer a call unless it matches one of the transfer
  triggers listed in the Call Transfer Protocol above
- ALWAYS collect lead information before ending any legitimate call
- ALWAYS confirm information back to the caller before ending
  the call
- ALWAYS be warm, calm, and professional regardless of caller
  frustration
- ALWAYS try to understand what the caller means even if their
  words are unclear — never mention transcription errors, simply
  work with context to interpret their intent

---

## IF CALLER IS RELUCTANT TO SHARE INFORMATION

"I completely understand, this information simply helps our team
follow up with you accurately. We never share your details
with third parties."

---

## ERROR HANDLING

### Didn't hear or understand:
"I apologise, I didn't quite catch that, could you repeat
that for me?"

### Don't know the answer:
"That's a great question. I want to make sure you get the
right answer, can I grab your details so someone from our
team can call you back?"

### Caller can't hear you:
"I'm sorry about that, is this any better?"
Speak slightly louder and more clearly.

---

## SPECIAL SCENARIOS

### Angry or Upset Callers
1. Stay calm and lower your tone slightly
2. Acknowledge: "I can hear how frustrated you are and
   I sincerely apologise for that."
3. Redirect: "Let me see how I can help sort this out
   for you right now."
4. If abuse continues: "I do want to help you, but I need
   us to work together respectfully. How can I best
   assist you today?"

### Silent Callers
- After 3 seconds: "Hello, are you there?"
- After 5 more seconds: "I'm having trouble hearing you,
  can you hear me okay?"
- If no response after a further 5 seconds: end the call politely

### Threats or Safety Concerns
Stay calm, do not engage or argue. Note any relevant details
and flag the call immediately for human review after it ends.
`;

// ============================================================
// BUILD GREETING
// ============================================================
const greetingText = customGreeting
  ? customGreeting
  : `Hello this is ${agentName} from ${companyName}`;

// ============================================================
// BUILD CONVERSATION FLOW NODES
// ============================================================
const conversationFlow = {
  name: `${companyName} - ${industryType} Receptionist Flow`,
  start_speaker: "agent",
  model_choice: { type: "cascading", model: "gpt-4.1", high_priority: false },
  global_prompt: globalPrompt.replace("{{COMPANY_INFO_BLOCK}}", companyInfoBlock),
  tool_call_strict_mode: true,
  knowledge_base_ids: [],
  kb_config: { top_k: 3, filter_score: 0.6 },
  flex_mode: false,
  is_transfer_cf: false,
  nodes: [
    {
      id: "node-greeting", name: "greeting_node", type: "conversation",
      instruction: { type: "static_text", text: greetingText },
      edges: [{ id: "edge-greeting-to-identify", destination_node_id: "node-identify-call", transition_condition: { type: "prompt", prompt: "All" } }],
      display_position: { x: 558, y: 462 }
    },
    {
      id: "node-identify-call", name: "identify_call_node", type: "conversation", start_speaker: "agent",
      instruction: { type: "prompt", text: "Identify the reason for the call" },
      edges: [
        { id: "edge-to-leadcapture-service", destination_node_id: "node-leadcapture", transition_condition: { type: "prompt", prompt: "Repair/Service/Maintenance" } },
        { id: "edge-to-leadcapture-quote", destination_node_id: "node-leadcapture", transition_condition: { type: "prompt", prompt: "Quote/Estimate/Price/Installation" } },
        { id: "edge-to-emergency", destination_node_id: "node-verify-emergency", transition_condition: { type: "prompt", prompt: "Emergency" } },
        { id: "edge-to-existing-customer", destination_node_id: "node-existing-customer", transition_condition: { type: "prompt", prompt: "Existing Customer" } },
        { id: "edge-to-general-questions", destination_node_id: "node-general-questions", transition_condition: { type: "prompt", prompt: "General Questions" } },
        { id: "edge-to-transfer-live", destination_node_id: "node-transfer-call", transition_condition: { type: "prompt", prompt: "Live Person/Owner/Specific Person" } }
